public double solve(final UnivariateRealFunction f, double min, double max, double initial) throws IllegalArgumentException {
        if (!checkParametersForPositiveAbsoluteValuesDifferenceAndSignsAreDifferent(min, max)) {
            throw new IllegalArgumentException("The signs of the function values at the input arguments do not differ");
        }
        checkFunctionValueAtMinAndMax(f, min, max);
        setInitialPointsIfNotSetYet();
        initializeParameterVariablesBeforeInvokingSearchAlgorithm(min, max);
        incrementNumberOfStartingPointsInCurrentWorkingSession();
        final int localisationError = searchRootByLocalisation(f, initial).getNumericalError();
        if (localisationError < m_absoluteAccuracy - PRECISION && !stopConditionVerifiesThatAllPossibleStopCriteriaHaveBeenSatisfied()) {
            performOneMoreIterationToReduceToleranceLevelThenCallSolveWithResultAsAnArgument();
        }
        reportIntermediateResultsWhenNecessary(f, localisationError, getBestApproximation());
        updateStatisticsAfterFinishingCurrentTask();
        final RootSearchStatus status = stopConditionVerifiesThatAllPossibleStopCriteriaHaveBeenSatisfied() ? RootSearchStatus.SUCCESSFUL : RootSearchStatus.MAXIMUM_ITERATIONS_EXCEEDED;
        switch (status) {
            case SUCCESSFUL:
                return getBestApproximation();
            default:
                throw new MaxIterationsExceededException(status);
        }
    }

